package main.rice.node;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * An abstract class representing a node in a "type tree" that can generate values of a
 * specific Python type. Each node has an exhaustive domain and a random domain, both
 * represented as lists of integers. The meaning of these integers depends on the
 * concrete subclass.
 *
 * @param <T> the type of Python object generated by this node
 */
public abstract class APyNode<T extends APyObj> {

    /**
     * The exhaustive domain for this node. For scalar types, these are the actual
     * values; for iterable types, these are the allowed sizes.
     */
    protected List<Integer> exDomain;

    /**
     * The random domain for this node. Same interpretation as exDomain.
     */
    protected List<Integer> ranDomain;

    /**
     * Returns the exhaustive domain for this node.
     *
     * @return the exhaustive domain
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Returns the random domain for this node.
     *
     * @return the random domain
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param domain the new exhaustive domain
     */
    public void setExDomain(List<Integer> domain) {
        this.exDomain = new ArrayList<>(domain);
    }

    /**
     * Sets the random domain for this node.
     *
     * @param domain the new random domain
     */
    public void setRanDomain(List<Integer> domain) {
        this.ranDomain = new ArrayList<>(domain);
    }

    /**
     * Generates all exhaustive values for this node based on the exhaustive domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<T> genExVals();

    /**
     * Generates a single random value for this node based on the random domain.
     *
     * @return a randomly generated value
     */
    public abstract T genRandVal();
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * An abstract class representing a node that generates iterable Python objects
 * (lists, sets, tuples). It has a single left child node that generates the
 * elements of the iterable.
 *
 * @param <InnerType> the type of element in the iterable
 * @param <OuterType> the type of the iterable object generated
 */
public abstract class AIterablePyNode<InnerType extends APyObj, OuterType extends APyObj>
        extends APyNode<OuterType> {

    /**
     * The child node used to generate elements of the iterable.
     */
    protected APyNode<InnerType> leftChild;

    /**
     * Returns the left child node.
     *
     * @return the left child node
     */
    public APyNode<InnerType> getLeftChild() {
        return this.leftChild;
    }

    /**
     * Generates all ordered tuples of the given length from the given list of elements,
     * with repetition allowed (i.e., Cartesian product of elements with itself length
     * times).
     *
     * @param elements the elements to combine
     * @param length   the desired length
     * @param <T>      the element type
     * @return all ordered lists of the given length
     */
    protected static <T> List<List<T>> cartesianProductWithRep(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        if (length == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        List<List<T>> smaller = cartesianProductWithRep(elements, length - 1);
        for (T elem : elements) {
            for (List<T> prev : smaller) {
                List<T> newList = new ArrayList<>();
                newList.add(elem);
                newList.addAll(prev);
                result.add(newList);
            }
        }
        return result;
    }

    /**
     * Generates all combinations of the given size from the given list of elements,
     * without repetition (i.e., all subsets of size 'size').
     *
     * @param elements the elements to choose from
     * @param size     the desired subset size
     * @param <T>      the element type
     * @return all combinations as lists (preserving relative order)
     */
    protected static <T> List<List<T>> combinations(List<T> elements, int size) {
        List<List<T>> result = new ArrayList<>();
        if (size == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        if (elements.size() < size) {
            return result;
        }
        for (int i = 0; i <= elements.size() - size; i++) {
            T first = elements.get(i);
            List<List<T>> rest = combinations(elements.subList(i + 1, elements.size()), size - 1);
            for (List<T> combo : rest) {
                List<T> newList = new ArrayList<>();
                newList.add(first);
                newList.addAll(combo);
                result.add(newList);
            }
        }
        return result;
    }
}

