/**
 * A node that generates Python list objects. The domain specifies allowed lengths.
 * Elements are generated by the left child node.
 *
 * @param <T> the type of element in the list
 */
public class PyListNode<T extends APyObj> extends AIterablePyNode<T, PyListObj<T>> {

    /**
     * Constructs a PyListNode with the given child node for element generation.
     *
     * @param child the node used to generate list elements
     */
    public PyListNode(APyNode<T> child) {
        this.leftChild = child;
    }

    /**
     * Generates all exhaustive lists. For each length in exDomain, generates all
     * ordered lists of that length using the exhaustive values of the child node
     * (with repetition allowed).
     *
     * @return a set of all exhaustive PyListObj values
     */
    @Override
    public Set<PyListObj<T>> genExVals() {
        Set<PyListObj<T>> result = new LinkedHashSet<>();
        List<T> innerVals = new ArrayList<>(this.leftChild.genExVals());

        for (Integer len : this.exDomain) {
            List<List<T>> combos = cartesianProductWithRep(innerVals, len);
            for (List<T> combo : combos) {
                result.add(new PyListObj<>(combo));
            }
        }
        return result;
    }

    /**
     * Generates a single random list. Picks a random length from ranDomain, then
     * picks that many random elements from the child node.
     *
     * @return a randomly generated PyListObj
     */
    @Override
    public PyListObj<T> genRandVal() {
        Random random = new Random();
        int len = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        List<T> elements = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            elements.add(this.leftChild.genRandVal());
        }
        return new PyListObj<>(elements);
    }
}

