 */
public class PySetNode<T extends APyObj> extends AIterablePyNode<T, PySetObj<T>> {

    /**
     * Constructs a PySetNode with the given child node for element generation.
     *
     * @param child the node used to generate set elements
     */
    public PySetNode(APyNode<T> child) {
        this.leftChild = child;
    }

    /**
     * Generates all exhaustive sets. For each size in exDomain, generates all
     * subsets of that size from the child node's exhaustive values.
     *
     * @return a set of all exhaustive PySetObj values
     */
    @Override
    public Set<PySetObj<T>> genExVals() {
        Set<PySetObj<T>> result = new LinkedHashSet<>();
        List<T> innerVals = new ArrayList<>(this.leftChild.genExVals());

        for (Integer size : this.exDomain) {
            List<List<T>> combos = combinations(innerVals, size);
            for (List<T> combo : combos) {
                Set<T> innerSet = new LinkedHashSet<>(combo);
                result.add(new PySetObj<>(innerSet));
            }
        }
        return result;
    }

    /**
     * Generates a single random set. Picks a random size from ranDomain, then
     * repeatedly calls the child node's genRandVal() to collect distinct elements.
     *
     * @return a randomly generated PySetObj
     */
    @Override
    public PySetObj<T> genRandVal() {
        Random random = new Random();
        int size = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        Set<T> elements = new LinkedHashSet<>();
        int maxAttempts = size * 100 + 100;
        int attempts = 0;
        while (elements.size() < size && attempts < maxAttempts) {
            elements.add(this.leftChild.genRandVal());
            attempts++;
        }
        return new PySetObj<>(elements);
    }
}

