/**
 * A node that generates Python dictionary objects. The domain specifies allowed sizes
 * (number of key-value pairs). Keys are generated by the left child node, and values
 * are generated by the right child node.
 *
 * @param <K> the type of dictionary keys
 * @param <V> the type of dictionary values
 */
public class PyDictNode<K extends APyObj, V extends APyObj> extends APyNode<PyDictObj<K, V>> {

    /**
     * The node used to generate dictionary keys.
     */
    private final APyNode<K> leftChild;

    /**
     * The node used to generate dictionary values.
     */
    private final APyNode<V> rightChild;

    /**
     * Constructs a PyDictNode with the given key and value child nodes.
     *
     * @param leftChild  the node for generating keys
     * @param rightChild the node for generating values
     */
    public PyDictNode(APyNode<K> leftChild, APyNode<V> rightChild) {
        this.leftChild = leftChild;
        this.rightChild = rightChild;
    }

    /**
     * Returns the left child (key generator) node.
     *
     * @return the left child node
     */
    public APyNode<K> getLeftChild() {
        return this.leftChild;
    }

    /**
     * Returns the right child (value generator) node.
     *
     * @return the right child node
     */
    public APyNode<V> getRightChild() {
        return this.rightChild;
    }

    /**
     * Generates all exhaustive dictionaries. For each size in exDomain, generates all
     * possible dictionaries of that size. Keys are chosen without replacement from the
     * key node's exhaustive values, and each key is independently mapped to any value
     * from the value node's exhaustive values.
     *
     * @return a set of all exhaustive PyDictObj values
     */
    @Override
    public Set<PyDictObj<K, V>> genExVals() {
        Set<PyDictObj<K, V>> result = new LinkedHashSet<>();
        List<K> keyVals = new ArrayList<>(this.leftChild.genExVals());
        List<V> valVals = new ArrayList<>(this.rightChild.genExVals());

        for (Integer size : this.exDomain) {
            // Get all combinations of 'size' keys (without replacement)
            List<List<K>> keyCombos = combinations(keyVals, size);
            for (List<K> keys : keyCombos) {
                // For each key combo, get all value tuples (with replacement, one per key)
                List<List<V>> valueTuples = cartesianProductWithRep(valVals, size);
                for (List<V> values : valueTuples) {
                    Map<K, V> map = new LinkedHashMap<>();
                    for (int i = 0; i < keys.size(); i++) {
                        map.put(keys.get(i), values.get(i));
                    }
                    result.add(new PyDictObj<>(map));
                }
            }
        }
        return result;
    }

    /**
     * Generates a single random dictionary. Picks a random size from ranDomain, then
     * picks that many random key-value pairs using the child nodes. Keys are collected
     * without replacement.
     *
     * @return a randomly generated PyDictObj
     */
    @Override
    public PyDictObj<K, V> genRandVal() {
        Random random = new Random();
        int size = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        Map<K, V> map = new LinkedHashMap<>();
        int maxAttempts = size * 100 + 100;
        int attempts = 0;
        while (map.size() < size && attempts < maxAttempts) {
            K key = this.leftChild.genRandVal();
            V val = this.rightChild.genRandVal();
            if (!map.containsKey(key)) {
                map.put(key, val);
            }
            attempts++;
        }
        return new PyDictObj<>(map);
    }

    /**
     * Generates all combinations of the given size from elements (without repetition).
     */
    private static <T> List<List<T>> combinations(List<T> elements, int size) {
        List<List<T>> result = new ArrayList<>();
        if (size == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        if (elements.size() < size) {
            return result;
        }
        for (int i = 0; i <= elements.size() - size; i++) {
            T first = elements.get(i);
            List<List<T>> rest = combinations(elements.subList(i + 1, elements.size()), size - 1);
            for (List<T> combo : rest) {
                List<T> newList = new ArrayList<>();
                newList.add(first);
                newList.addAll(combo);
                result.add(newList);
            }
        }
        return result;
    }

    /**
     * Generates all ordered tuples of the given length from elements, with repetition.
     */
    private static <T> List<List<T>> cartesianProductWithRep(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        if (length == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        List<List<T>> smaller = cartesianProductWithRep(elements, length - 1);
        for (T elem : elements) {
            for (List<T> prev : smaller) {
                List<T> newList = new ArrayList<>();
                newList.add(elem);
                newList.addAll(prev);
                result.add(newList);
            }
        }
        return result;
    }
}

